import{_ as t,c as e,S as a,o as i}from"./chunks/framework.BjmDYXuv.js";const k=JSON.parse('{"title":"Benchmark Tasks","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tasks.md","filePath":"guide/tasks.md","lastUpdated":1776321806000}'),n={name:"guide/tasks.md"};function l(r,s,h,o,d,p){return i(),e("div",null,s[0]||(s[0]=[a(`<h1 id="benchmark-tasks" tabindex="-1">Benchmark Tasks <a class="header-anchor" href="#benchmark-tasks" aria-label="Permalink to &quot;Benchmark Tasks&quot;">​</a></h1><p>ColliderML ships a small catalogue of benchmark tasks so that every model can be compared on an equal footing. Each task defines:</p><ul><li>a <strong>dataset</strong> to draw events from (e.g. <code>ttbar_pu200</code>)</li><li>a <strong>held-out eval range</strong> (event IDs) that participants must not train on</li><li>the <strong>inputs</strong> a model is allowed to see</li><li>a set of <strong>metrics</strong> with directions (higher-is-better or lower-is-better)</li></ul><p>This page is the conceptual tour. For the complete API, see <a href="./../library/tasks.html"><code>colliderml.tasks</code></a>.</p><h2 id="the-catalogue-at-a-glance" tabindex="-1">The catalogue at a glance <a class="header-anchor" href="#the-catalogue-at-a-glance" aria-label="Permalink to &quot;The catalogue at a glance&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Task name</th><th style="text-align:left;">Dataset</th><th style="text-align:left;">Inputs</th><th style="text-align:left;">Primary metric</th><th style="text-align:left;">What it measures</th></tr></thead><tbody><tr><td style="text-align:left;"><code>tracking</code></td><td style="text-align:left;"><code>ttbar_pu200</code></td><td style="text-align:left;"><code>tracker_hits</code></td><td style="text-align:left;"><code>trackml_eff</code></td><td style="text-align:left;">Track reconstruction quality</td></tr><tr><td style="text-align:left;"><code>jets</code></td><td style="text-align:left;"><code>ttbar_pu0</code></td><td style="text-align:left;"><code>tracks</code>, <code>calo_hits</code></td><td style="text-align:left;"><code>btag_auc</code></td><td style="text-align:left;">Jet flavour tagging (b / c / light)</td></tr><tr><td style="text-align:left;"><code>anomaly</code></td><td style="text-align:left;">mixed SM + BSM</td><td style="text-align:left;"><code>tracks</code>, <code>calo_hits</code></td><td style="text-align:left;"><code>auroc</code></td><td style="text-align:left;">BSM event detection against SM background</td></tr><tr><td style="text-align:left;"><code>tracking_latency</code></td><td style="text-align:left;"><code>ttbar_pu200</code></td><td style="text-align:left;"><code>tracker_hits</code></td><td style="text-align:left;"><code>events_per_sec</code></td><td style="text-align:left;">Inference throughput for tracking</td></tr><tr><td style="text-align:left;"><code>tracking_small</code></td><td style="text-align:left;"><code>ttbar_pu200</code></td><td style="text-align:left;"><code>tracker_hits</code></td><td style="text-align:left;"><code>trackml_eff</code> per tier</td><td style="text-align:left;">Tracking under a parameter budget</td></tr><tr><td style="text-align:left;"><code>data_loading</code></td><td style="text-align:left;"><code>ttbar_pu200</code></td><td style="text-align:left;"><code>tracker_hits</code></td><td style="text-align:left;"><code>events_per_sec_local</code></td><td style="text-align:left;">Raw data loading throughput</td></tr></tbody></table><p>Get the list programmatically at any time:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml.tasks</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(colliderml.tasks.list_tasks())</span></span></code></pre></div><h2 id="installing-the-task-runner" tabindex="-1">Installing the task runner <a class="header-anchor" href="#installing-the-task-runner" aria-label="Permalink to &quot;Installing the task runner&quot;">​</a></h2><p>The task registry is in the base install, but the reference baselines (BDT for jets, IsolationForest for anomaly detection) use scikit-learn. Install the optional extra to get them:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install &quot;colliderml[tasks]&quot;</span></span></code></pre></div><p>You can evaluate your own predictions against a task without the <code>tasks</code> extra — you only need it if you want to run the shipped baselines verbatim.</p><h2 id="the-scoring-contract" tabindex="-1">The scoring contract <a class="header-anchor" href="#the-scoring-contract" aria-label="Permalink to &quot;The scoring contract&quot;">​</a></h2><p>Every task exposes three methods on its instance:</p><ol><li><strong><code>load_eval_inputs()</code></strong> — returns the held-out eval data as a dict of pyarrow Tables. Users call this to build their inference pipeline; the backend calls it to run baselines on demand.</li><li><strong><code>validate_predictions(preds)</code></strong> — raises <code>ValueError</code> if your submission has the wrong columns, sums, coverage, etc. Run this locally before uploading anything.</li><li><strong><code>score(preds)</code></strong> — returns <code>{metric_name: value}</code>.</li></ol><p>The top-level helper <code>colliderml.tasks.evaluate</code> chains the last two:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml.tasks</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scores </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml.tasks.evaluate(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tracking&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my_tracks.parquet&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(scores)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># {&#39;trackml_eff&#39;: 0.87, &#39;fake_rate&#39;: 0.03, &#39;dup_rate&#39;: 0.04, &#39;physics_eff_pt1&#39;: 0.92}</span></span></code></pre></div><h2 id="eval-splits-—-what-can-i-train-on" tabindex="-1">Eval splits — &quot;what can I train on?&quot; <a class="header-anchor" href="#eval-splits-—-what-can-i-train-on" aria-label="Permalink to &quot;Eval splits — &quot;what can I train on?&quot;&quot;">​</a></h2><p>Each task withholds a range of event IDs (<code>eval_event_range</code>) for scoring. A valid submission covers <em>at least half</em> of that range — partial submissions are allowed so users can iterate quickly, but full coverage is required to win a credit award on the leaderboard.</p><p>Use the task&#39;s own <code>load()</code> helper to pull just the eval events:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">task </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml.tasks.get(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tracking&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hits </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> task.load(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">tables</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tracker_hits&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">event_range</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">task.eval_event_range)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># hits[&quot;tracker_hits&quot;] is a pyarrow Table with events 90_000..100_000</span></span></code></pre></div><p>For training, load the complement — events <em>outside</em> the eval range. The loader is explicit enough that &quot;this data is safe to train on&quot; is easy to enforce in your own pipeline.</p><h2 id="submitting-to-the-leaderboard" tabindex="-1">Submitting to the leaderboard <a class="header-anchor" href="#submitting-to-the-leaderboard" aria-label="Permalink to &quot;Submitting to the leaderboard&quot;">​</a></h2><p>Local evaluation gives you a preview. To earn credits and appear on the public leaderboard, submit to the backend:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml.tasks</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> colliderml.tasks.submit(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tracking&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my_tracks.parquet&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(result[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;scores&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># backend&#39;s canonical scores</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(result[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;credits_earned&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># non-zero if you beat a previous best</span></span></code></pre></div><p>Submission requires the <code>remote</code> extra (for <code>requests</code>) and a HuggingFace token — see <a href="./remote-simulation.html#prerequisites">Remote Simulation</a> for auth setup. The backend re-scores your submission against its held-out truth set (which is <em>not</em> bundled with the library, so you can&#39;t overfit on it) and awards credits on new bests.</p><h2 id="running-the-reference-baselines" tabindex="-1">Running the reference baselines <a class="header-anchor" href="#running-the-reference-baselines" aria-label="Permalink to &quot;Running the reference baselines&quot;">​</a></h2><p>Each task ships a simple reference baseline you can run as a module:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># CKF baseline for the tracking task — converts a pipeline run&#39;s</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># tracksummary_ambi.root into the task&#39;s expected parquet schema.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> colliderml.tasks.tracking.baselines.ckf </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --run-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./colliderml_output/ttbar_pu200_100evt/runs/0 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ckf_preds.parquet</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># GBDT baseline for jet classification</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> colliderml.tasks.jets.baselines.bdt </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --channel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ttbar_pu0 --max-events </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> --output bdt_preds.parquet</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># IsolationForest baseline for anomaly detection</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> colliderml.tasks.anomaly.baselines.isoforest </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iso_preds.parquet</span></span></code></pre></div><p>The BDT and IsolationForest baselines use scikit-learn; the CKF baseline only needs a completed pipeline run, which you can produce with <code>colliderml simulate</code> (see <a href="./simulation.html">Local Simulation</a>).</p><h2 id="systems-tasks-vs-physics-tasks" tabindex="-1">Systems tasks vs. physics tasks <a class="header-anchor" href="#systems-tasks-vs-physics-tasks" aria-label="Permalink to &quot;Systems tasks vs. physics tasks&quot;">​</a></h2><p>The first three tasks (<code>tracking</code>, <code>jets</code>, <code>anomaly</code>) are <strong>physics tasks</strong> — they measure the quality of a model&#39;s output against truth.</p><p>The last three (<code>tracking_latency</code>, <code>tracking_small</code>, <code>data_loading</code>) are <strong>systems tasks</strong> — they measure operational properties (wall-clock time, parameter count, I/O throughput). Systems tasks exist because the best scientific model is not always the most useful: a 10 GB transformer that wins the tracking leaderboard is worse than a 10 kB network that hits 95% of its score if you actually have to deploy it at collider trigger latencies.</p><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li>Browse the <a href="./../library/tasks.html">API reference</a> for every function signature</li><li>Read about <a href="./remote-simulation.html">remote simulation</a> to generate training data</li><li>Check the live <a href="https://huggingface.co/spaces/ColliderML/leaderboard" target="_blank" rel="noreferrer">Leaderboard</a> (deployed from this repo&#39;s <code>spaces/leaderboard/</code>)</li><li>Open a PR to add a new task or baseline — contributors earn credits!</li></ul>`,35)]))}const g=t(n,[["render",l]]);export{k as __pageData,g as default};
